import React, { useState } from 'react';
import { useData } from '../../context/DataContext';

// Helper check ngày
const isSameDay = (d1, d2) => d1.toDateString() === d2.toDateString();
const isSameMonth = (d1, d2) => d1.getMonth() === d2.getMonth() && d1.getFullYear() === d2.getFullYear();
const isSameWeek = (d1, d2) => {
    const start = new Date(d2);
    start.setHours(0,0,0,0);
    start.setDate(start.getDate() - start.getDay() + 1); // Thứ 2
    const end = new Date(start);
    end.setDate(end.getDate() + 6);
    return d1 >= start && d1 <= end;
};

const Reports = () => {
  const { tasks, staffList } = useData();
  const [timeFilter, setTimeFilter] = useState('month'); // day, week, month

  // 1. LỌC DATA CHO TIẾN ĐỘ CÔNG VIỆC (CHỈ OP ADMIN GIAO)
  // Logic: Task do Op Admin giao thường không có fromScheduleId
  const opAdminTasks = tasks.filter(t => !t.fromScheduleId);

  // Tính toán thống kê cho Op Admin Tasks
  const totalOpTasks = opAdminTasks.length;
  const completedOpTasks = opAdminTasks.filter(t => t.status === 'completed').length;
  const progressPercent = totalOpTasks > 0 ? Math.round((completedOpTasks / totalOpTasks) * 100) : 0;

  // 2. LỌC DATA CHO BÁO CÁO CHẤM CÔNG (THEO LỊCH SCHEDULER)
  // Logic: Task sinh ra từ Scheduler có fromScheduleId
  const scheduleTasks = tasks.filter(t => t.fromScheduleId);
  
  // Áp dụng bộ lọc thời gian cho Schedule Tasks
  const filteredScheduleTasks = scheduleTasks.filter(t => {
      const taskDate = new Date(t.startTime);
      const now = new Date();
      if (timeFilter === 'day') return isSameDay(taskDate, now);
      if (timeFilter === 'week') return isSameWeek(taskDate, now);
      if (timeFilter === 'month') return isSameMonth(taskDate, now);
      return true;
  });

  return (
    <div style={{ paddingBottom: '40px' }}>
      <h2 style={{ color: '#003366', borderBottom: '1px solid #e5e7eb', paddingBottom: '15px' }}>Báo cáo Tổng hợp</h2>

      {/* --- PHẦN 1: BÁO CÁO CHẤM CÔNG (THEO LỊCH SCHEDULER) --- */}
      <div style={{ marginTop: '30px', background: 'white', padding: '24px', borderRadius: '16px', boxShadow: '0 4px 6px rgba(0,0,0,0.05)' }}>
          <div style={{display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'20px'}}>
              <h3 style={{ margin: 0, color: '#003366' }}>📅 Báo cáo Chấm công (Theo Lịch)</h3>
              <select 
                  value={timeFilter} 
                  onChange={(e) => setTimeFilter(e.target.value)}
                  style={{padding:'8px', borderRadius:'8px', border:'1px solid #ccc', outline:'none', fontWeight:'600', color:'#4b5563'}}
              >
                  <option value="day">Hôm nay</option>
                  <option value="week">Tuần này</option>
                  <option value="month">Tháng này</option>
              </select>
          </div>

          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem' }}>
              <thead>
                  <tr style={{ background: '#f3f4f6', color: '#374151', textAlign: 'left' }}>
                      <th style={{ padding: '12px', borderRadius: '8px 0 0 8px' }}>Nhân sự</th>
                      <th>Ca / Lịch làm việc</th>
                      <th>Thời gian</th>
                      <th>Trạng thái</th>
                      <th style={{ borderRadius: '0 8px 8px 0' }}>Tiến độ</th>
                  </tr>
              </thead>
              <tbody>
                  {filteredScheduleTasks.length > 0 ? filteredScheduleTasks.map(t => (
                      <tr key={t.id} style={{ borderBottom: '1px solid #f9fafb' }}>
                          <td style={{ padding: '12px', fontWeight: '600', color: '#1f2937' }}>{t.assigneeName}</td>
                          <td>
                              <div>{t.title}</div>
                              <div style={{fontSize:'0.75rem', color:'#6b7280'}}>{t.assignedRole}</div>
                          </td>
                          <td>
                              {new Date(t.startTime).toLocaleDateString('vi-VN')} <br/>
                              <span style={{fontSize:'0.8rem', color:'#6b7280'}}>
                                  {new Date(t.startTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})} - 
                                  {new Date(t.endTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                              </span>
                          </td>
                          <td>
                              {t.status === 'completed' ? 
                                  <span style={{color:'green', fontWeight:'bold', background:'#dcfce7', padding:'2px 8px', borderRadius:'10px', fontSize:'0.75rem'}}>Hoàn thành</span> : 
                                  <span style={{color:'#d97706', background:'#fef3c7', padding:'2px 8px', borderRadius:'10px', fontSize:'0.75rem'}}>Đang/Chờ</span>
                              }
                          </td>
                          <td>{t.progress}%</td>
                      </tr>
                  )) : (
                      <tr><td colSpan="5" style={{padding:'20px', textAlign:'center', color:'#9ca3af', fontStyle:'italic'}}>Không có dữ liệu chấm công cho bộ lọc này.</td></tr>
                  )}
              </tbody>
          </table>
      </div>

      {/* --- PHẦN 2: TIẾN ĐỘ CÔNG VIỆC (CHỈ OP ADMIN) --- */}
      <div style={{ marginTop: '30px', background: 'white', padding: '24px', borderRadius: '16px', boxShadow: '0 4px 6px rgba(0,0,0,0.05)' }}>
          <h3 style={{ margin: '0 0 20px 0', color: '#003366' }}>📊 Tiến độ Công việc (Operational Admin giao)</h3>
          
          <div style={{display:'flex', gap:'20px', marginBottom:'20px'}}>
               <div style={{flex:1, background:'#f0f9ff', padding:'15px', borderRadius:'12px', border:'1px solid #bae6fd'}}>
                   <div style={{fontSize:'0.85rem', color:'#0369a1', fontWeight:'600'}}>Tổng nhiệm vụ</div>
                   <div style={{fontSize:'1.5rem', fontWeight:'bold', color:'#0c4a6e'}}>{totalOpTasks}</div>
               </div>
               <div style={{flex:1, background:'#f0fdf4', padding:'15px', borderRadius:'12px', border:'1px solid #bbf7d0'}}>
                   <div style={{fontSize:'0.85rem', color:'#15803d', fontWeight:'600'}}>Đã hoàn thành</div>
                   <div style={{fontSize:'1.5rem', fontWeight:'bold', color:'#14532d'}}>{completedOpTasks}</div>
               </div>
               <div style={{flex:1, background:'#fff7ed', padding:'15px', borderRadius:'12px', border:'1px solid #fed7aa'}}>
                   <div style={{fontSize:'0.85rem', color:'#c2410c', fontWeight:'600'}}>Tỷ lệ hoàn thành</div>
                   <div style={{fontSize:'1.5rem', fontWeight:'bold', color:'#7c2d12'}}>{progressPercent}%</div>
               </div>
          </div>

          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem' }}>
            <thead>
               <tr style={{ textAlign: 'left', borderBottom: '2px solid #f3f4f6' }}>
                 <th style={{ padding: '10px' }}>Nhiệm vụ</th>
                 <th>Người phụ trách</th>
                 <th>Hạn chót</th>
                 <th>Tiến độ</th>
               </tr>
            </thead>
            <tbody>
               {opAdminTasks.map(t => (
                 <tr key={t.id} style={{ borderBottom: '1px solid #f9f9f9' }}>
                    <td style={{ padding: '10px' }}>
                        <strong>{t.title}</strong>
                        <div style={{ fontSize: '0.75rem', color: '#6b7280' }}>{t.paymentType}</div>
                    </td>
                    <td>{t.assigneeName}</td>
                    <td>{new Date(t.endTime).toLocaleDateString('vi-VN')}</td>
                    <td>
                        <div style={{ width: '100px', height: '6px', background: '#e5e7eb', borderRadius: '3px', overflow: 'hidden' }}>
                            <div style={{ width: `${t.progress}%`, height: '100%', background: t.progress === 100 ? '#10b981' : '#003366' }}></div>
                        </div>
                        <span style={{fontSize:'0.75rem'}}>{t.progress}%</span>
                    </td>
                 </tr>
               ))}
               {opAdminTasks.length === 0 && <tr><td colSpan="4" style={{padding:'20px', textAlign:'center', color:'#9ca3af'}}>Chưa có nhiệm vụ nào.</td></tr>}
            </tbody>
         </table>
      </div>
    </div>
  );
};

export default Reports;
